Here is the flake I am using, if it is at all helpful...

```nix
{
  description = "cython flake";

  inputs = {
    nixpkgs.follows = "maipkgs/nixpkgs";
    maipkgs.url = "github:stephen-huan/maipkgs";
  };

  outputs = { self, nixpkgs, maipkgs }:
    let
      inherit (nixpkgs) lib;
      systems = lib.systems.flakeExposed;
      eachDefaultSystem = f: builtins.foldl' lib.attrsets.recursiveUpdate { }
        (map f systems);
    in
    eachDefaultSystem (system:
      let
        pkgs = nixpkgs.legacyPackages.${system};
        inherit (maipkgs.legacyPackages.${system}) python;
        python' = python.withPackages (ps: with ps; [ cython setuptools ]);
      in
      {
        devShells.${system}.default = pkgs.mkShell {
          packages = [
            python'
          ];
        };
      }
    );
}
```

I agree that there is probably no actual issue. I will just... ignore it (or apply your patch :p).
